import { useEffect, useState, useRef } from 'react'
import { AnimatePresence, motion } from 'framer-motion'

const LOGO_SRC = 'data:image/png;base64,'

const MESSAGES = [
  'Polishing the vault…',
  'Waking the goldsmith…',
  'Counting the karats…',
  'Dusting off the jewels…',
  'Aligning the crown settings…',
  'Almost there…',
]

const API = import.meta.env.VITE_API_URL

async function pingBackend() {
  try {
    const res = await fetch(`${API}/api/lots/next-number`, {
      signal: AbortSignal.timeout(8000),
    })
    return res.ok
  } catch {
    return false
  }
}

export default function WakeUpOverlay({ onReady }) {
  const [visible, setVisible]   = useState(true)
  const [msgIdx, setMsgIdx]     = useState(0)
  const [dots, setDots]         = useState('')
  const [shimmer, setShimmer]   = useState(false)
  const intervalRef             = useRef(null)
  const msgRef                  = useRef(null)
  const dotsRef                 = useRef(null)

  // rotating messages
  useEffect(() => {
    msgRef.current = setInterval(() => {
      setMsgIdx(i => (i + 1) % MESSAGES.length)
    }, 2200)
    return () => clearInterval(msgRef.current)
  }, [])

  // animated dots
  useEffect(() => {
    let d = 0
    dotsRef.current = setInterval(() => {
      d = (d + 1) % 4
      setDots('.'.repeat(d))
    }, 400)
    return () => clearInterval(dotsRef.current)
  }, [])

  // backend polling
  useEffect(() => {
    let attempts = 0

    const poll = async () => {
      attempts++
      const ok = await pingBackend()
      if (ok) {
        clearInterval(intervalRef.current)
        setShimmer(true)
        setTimeout(() => {
          setVisible(false)
          onReady?.()
        }, 1200)
      }
    }

    poll()
    intervalRef.current = setInterval(poll, 3000)
    return () => clearInterval(intervalRef.current)
  }, [onReady])

  return (
    <AnimatePresence>
      {visible && (
        <motion.div
          initial={{ opacity: 1 }}
          exit={{ opacity: 0, scale: 1.03 }}
          transition={{ duration: 0.9, ease: [0.4, 0, 0.2, 1] }}
          style={styles.overlay}
        >
          {/* noise grain texture */}
          <div style={styles.grain} />

          {/* radial glow behind logo */}
          <motion.div
            animate={{ opacity: [0.35, 0.7, 0.35], scale: [1, 1.12, 1] }}
            transition={{ duration: 3.5, repeat: Infinity, ease: 'easeInOut' }}
            style={styles.glow}
          />

          {/* floating diamond particles */}
          {DIAMONDS.map((d, i) => (
            <motion.div
              key={i}
              animate={{
                y: [d.startY, d.startY - 120],
                opacity: [0, 0.7, 0],
                rotate: [0, d.spin],
              }}
              transition={{
                duration: d.dur,
                repeat: Infinity,
                delay: d.delay,
                ease: 'easeOut',
              }}
              style={{ ...styles.particle, left: d.left, top: d.top, fontSize: d.size }}
            >
              ◆
            </motion.div>
          ))}

          {/* logo */}
          <motion.div
            animate={shimmer
              ? { scale: [1, 1.08, 0.96], opacity: [1, 1, 0] }
              : { scale: [1, 1.04, 1] }
            }
            transition={shimmer
              ? { duration: 0.9, ease: 'easeInOut' }
              : { duration: 2.8, repeat: Infinity, ease: 'easeInOut' }
            }
            style={styles.logoWrap}
          >
            {/* spinning ring */}
            <motion.div
              animate={{ rotate: 360 }}
              transition={{ duration: 6, repeat: Infinity, ease: 'linear' }}
              style={styles.spinRing}
            />
            {/* counter-spin ring */}
            <motion.div
              animate={{ rotate: -360 }}
              transition={{ duration: 9, repeat: Infinity, ease: 'linear' }}
              style={styles.spinRing2}
            />

            <img src={LOGO_SRC} alt="BJ Jewellers" style={styles.logo} />
          </motion.div>

          {/* shimmer bar */}
          <motion.div style={styles.barWrap}>
            <motion.div
              animate={shimmer
                ? { width: '100%', opacity: [1, 0] }
                : { width: ['0%', '65%', '0%'] }
              }
              transition={shimmer
                ? { duration: 0.8 }
                : { duration: 2.4, repeat: Infinity, ease: 'easeInOut' }
              }
              style={styles.bar}
            />
          </motion.div>

          {/* status message */}
          <AnimatePresence mode="wait">
            <motion.p
              key={msgIdx}
              initial={{ opacity: 0, y: 6 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -6 }}
              transition={{ duration: 0.4 }}
              style={styles.msg}
            >
              {MESSAGES[msgIdx]}{dots}
            </motion.p>
          </AnimatePresence>

          <p style={styles.sub}>Balaraam Jewellers</p>
        </motion.div>
      )}
    </AnimatePresence>
  )
}

/* ── random diamonds ────────────────────────────────────────────── */
const DIAMONDS = Array.from({ length: 14 }, (_, i) => ({
  left:   `${5 + (i * 6.8) % 90}%`,
  top:    `${20 + (i * 13) % 65}%`,
  startY: (i * 17) % 60,
  size:   `${7 + (i % 4) * 3}px`,
  spin:   (i % 2 === 0 ? 1 : -1) * (90 + i * 15),
  dur:    2.8 + (i % 5) * 0.7,
  delay:  (i * 0.4) % 3.5,
}))

/* ── styles ─────────────────────────────────────────────────────── */
const styles = {
  overlay: {
    position: 'fixed', inset: 0, zIndex: 9999,
    background: 'radial-gradient(ellipse at 50% 40%, #0f2a1a 0%, #060e08 70%, #020704 100%)',
    display: 'flex', flexDirection: 'column',
    alignItems: 'center', justifyContent: 'center',
    gap: 0, overflow: 'hidden',
  },
  grain: {
    position: 'absolute', inset: 0, pointerEvents: 'none', zIndex: 0,
    backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='n'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23n)' opacity='0.04'/%3E%3C/svg%3E")`,
    backgroundSize: '180px 180px', opacity: 0.5,
  },
  glow: {
    position: 'absolute', top: '50%', left: '50%',
    transform: 'translate(-50%, -58%)',
    width: 340, height: 340, borderRadius: '50%',
    background: 'radial-gradient(circle, rgba(212,175,55,0.22) 0%, transparent 70%)',
    pointerEvents: 'none', zIndex: 1,
  },
  particle: {
    position: 'absolute', color: '#d4af37', zIndex: 2,
    pointerEvents: 'none', opacity: 0,
    textShadow: '0 0 6px rgba(212,175,55,0.8)',
  },
  logoWrap: {
    position: 'relative', zIndex: 3,
    display: 'flex', alignItems: 'center', justifyContent: 'center',
    width: 200, height: 200,
    filter: 'drop-shadow(0 0 28px rgba(212,175,55,0.55)) drop-shadow(0 8px 24px rgba(0,0,0,0.7))',
    marginBottom: 36,
  },
  spinRing: {
    position: 'absolute', inset: -16,
    borderRadius: '50%',
    border: '1.5px solid transparent',
    borderTopColor: 'rgba(212,175,55,0.7)',
    borderRightColor: 'rgba(212,175,55,0.2)',
    pointerEvents: 'none',
  },
  spinRing2: {
    position: 'absolute', inset: -28,
    borderRadius: '50%',
    border: '1px solid transparent',
    borderTopColor: 'rgba(212,175,55,0.35)',
    borderLeftColor: 'rgba(212,175,55,0.15)',
    pointerEvents: 'none',
  },
  logo: {
    width: 190, height: 190,
    objectFit: 'contain',
    borderRadius: 24,
  },
  barWrap: {
    width: 200, height: 2,
    background: 'rgba(212,175,55,0.15)',
    borderRadius: 99, overflow: 'hidden',
    position: 'relative', zIndex: 3,
    marginBottom: 24,
  },
  bar: {
    height: '100%',
    background: 'linear-gradient(90deg, transparent, #d4af37, #f5d77e, #d4af37, transparent)',
    borderRadius: 99,
    boxShadow: '0 0 8px rgba(212,175,55,0.8)',
  },
  msg: {
    fontFamily: '"Cormorant Garamond", "Garamond", Georgia, serif',
    fontSize: 15, fontStyle: 'italic',
    color: 'rgba(212,175,55,0.85)',
    letterSpacing: '0.08em',
    margin: 0, zIndex: 3,
    minHeight: 22, textAlign: 'center',
  },
  sub: {
    fontFamily: '"Cormorant Garamond", "Garamond", Georgia, serif',
    fontSize: 11,
    color: 'rgba(255,255,255,0.22)',
    letterSpacing: '0.35em', textTransform: 'uppercase',
    margin: '10px 0 0', zIndex: 3,
  },
}
